import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ResumeTemplate } from '../../../core/models/resume.model';

@Component({
  selector: 'app-recommended-templates',
  templateUrl: './recommended-templates.component.html'
})
export class RecommendedTemplatesComponent {
  @Input() templates: ResumeTemplate[] = [];
  @Input() favoriteIds = new Set<number>();
  @Output() preview = new EventEmitter<ResumeTemplate>();
  @Output() useTemplate = new EventEmitter<ResumeTemplate>();
  @Output() toggleFavorite = new EventEmitter<ResumeTemplate>();
}
<div class="shell-card p-6">
  <p class="eyebrow">Recommended for you</p>
  <h3 class="mt-2 text-3xl font-extrabold text-[#17172b]">Based on your role and experience</h3>
  <p class="mt-3 text-sm leading-7 text-[#667085]">Role: Java Developer | Experience: 3.5 years</p>
  <div class="mt-5 grid gap-5 md:grid-cols-2 xl:grid-cols-3">
    <app-template-card
      *ngFor="let template of templates"
      [template]="template"
      [favorite]="favoriteIds.has(template.id)"
      [atsScore]="94"
      [usedCountLabel]="'10,000+ students'"
      (preview)="preview.emit($event)"
      (useTemplate)="useTemplate.emit($event)"
      (toggleFavorite)="toggleFavorite.emit($event)">
    </app-template-card>
  </div>
</div>
